import java.util.ArrayList;
import java.util.HashMap;
import java.util.Map;

public class TestResultManager {
    private ArrayList<String> testNames;
    private HashMap<String, String> testResults;

    public TestResultManager() {
        testNames = new ArrayList<>();
        testResults = new HashMap<>();
    }

    public void addTestResult(String testName, String result) {
        if (!testNames.contains(testName)) {
            testNames.add(testName);
        }
        testResults.put(testName, result);
    }

    public String getTestResult(String testName) {
        return testResults.get(testName);
    }

    public ArrayList<String> getAllPassedTests() {
        ArrayList<String> passedTests = new ArrayList<>();
        for (Map.Entry<String, String> entry : testResults.entrySet()) {
            if ("PASS".equals(entry.getValue())) {
                passedTests.add(entry.getKey());
            }
        }
        return passedTests;
    }

    public int getTestCount() {
        return testNames.size();
    }

    public double getPassRate() {
        if (testNames.isEmpty()) {
            return 0.0;
        }
        int passCount = getAllPassedTests().size();
        return (passCount * 100.0) / testNames.size();
    }

    public static void main(String[] args) {
        TestResultManager manager = new TestResultManager();
        manager.addTestResult("LoginTest", "PASS");
        manager.addTestResult("LogoutTest", "PASS");
        manager.addTestResult("SearchTest", "FAIL");
        manager.addTestResult("CheckoutTest", "PASS");

        System.out.println("Total tests: " + manager.getTestCount());
        System.out.println("Pass rate: " + manager.getPassRate() + "%");
        System.out.println("Passed tests: " + manager.getAllPassedTests());
        System.out.println("Search test result: " + manager.getTestResult("SearchTest"));
    }
}
